import { useState } from 'react'
import Box from '@mui/material/Box'
import TextField from '@mui/material/TextField'
import Button from '@mui/material/Button'
import Paper from '@mui/material/Paper'
import Grid from '@mui/material/Grid'
import Typography from '@mui/material/Typography'
import IconButton from '@mui/material/IconButton'
import Autocomplete from '@mui/material/Autocomplete'
import Chip from '@mui/material/Chip'
import ToggleButtonGroup from '@mui/material/ToggleButtonGroup'
import ToggleButton from '@mui/material/ToggleButton'
import AddIcon from '@mui/icons-material/Add'
import DeleteIcon from '@mui/icons-material/Delete'
import Card from '@mui/material/Card'
import CardContent from '@mui/material/CardContent'
import Stack from '@mui/material/Stack'
import Tooltip from '@mui/material/Tooltip'
import HelpOutlineIcon from '@mui/icons-material/HelpOutline'
import { useQuery } from '@tanstack/react-query'
import { listTemplates } from '../../api/templates'
import type {
  CardCreate,
  HardnessLevel,
  ExampleSentence,
  TemplateResponse,
} from '../../types'

interface CardFormProps {
  initialValues?: Partial<CardCreate>
  onSubmit: (data: CardCreate) => void
  isLoading: boolean
  submitLabel: string
}

const SECTION_SPACING = 3

export default function CardForm({
  initialValues,
  onSubmit,
  isLoading,
  submitLabel,
}: CardFormProps) {
  const [front, setFront] = useState(initialValues?.front ?? '')
  const [back, setBack] = useState(initialValues?.back ?? '')
  const [partOfSpeech, setPartOfSpeech] = useState(
    initialValues?.part_of_speech ?? '',
  )
  const [gender, setGender] = useState(initialValues?.gender ?? '')
  const [pluralForm, setPluralForm] = useState(initialValues?.plural_form ?? '')
  const [pronunciation, setPronunciation] = useState(
    initialValues?.pronunciation ?? '',
  )
  const [notes, setNotes] = useState(initialValues?.notes ?? '')
  const [hardness, setHardness] = useState<HardnessLevel>(
    initialValues?.hardness_level ?? 'medium',
  )
  const [examples, setExamples] = useState<ExampleSentence[]>(
    initialValues?.examples ?? [{ sentence: '', translation: '' }],
  )
  const [synonyms, setSynonyms] = useState<string[]>(
    initialValues?.synonyms ?? [],
  )
  const [antonyms, setAntonyms] = useState<string[]>(
    initialValues?.antonyms ?? [],
  )
  const [tags, setTags] = useState<string[]>(initialValues?.tags ?? [])
  const [templateId, setTemplateId] = useState<string | null>(
    initialValues?.template_id ?? null,
  )
  const [customFields, setCustomFields] = useState<Record<string, any>>(
    initialValues?.custom_fields ?? {},
  )

  const { data: templates, isLoading: templatesLoading } = useQuery({
    queryKey: ['templates'],
    queryFn: () => listTemplates(0, 50, true),
  })

  const selectedTemplate =
    templates?.find((t: TemplateResponse) => t.id === templateId) ?? null

  const handleCustomFieldChange = (key: string, value: string) => {
    setCustomFields((prev) => ({ ...prev, [key]: value }))
  }

  const handleExampleChange = (
    index: number,
    field: keyof ExampleSentence,
    value: string,
  ) => {
    const updated = [...examples]
    updated[index] = { ...updated[index], [field]: value }
    setExamples(updated)
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    const filteredExamples = examples.filter(
      (ex) => ex.sentence.trim() || ex.translation.trim(),
    )
    onSubmit({
      front,
      back,
      part_of_speech: partOfSpeech || undefined,
      gender: gender || undefined,
      plural_form: pluralForm || undefined,
      pronunciation: pronunciation || undefined,
      notes: notes || undefined,
      hardness_level: hardness,
      template_id: templateId || undefined,
      custom_fields:
        Object.keys(customFields).length > 0 ? customFields : undefined,
      examples: filteredExamples.length > 0 ? filteredExamples : undefined,
      synonyms: synonyms.length > 0 ? synonyms : undefined,
      antonyms: antonyms.length > 0 ? antonyms : undefined,
      tags: tags.length > 0 ? tags : undefined,
    })
  }

  return (
    <Box component="form" onSubmit={handleSubmit}>
      <Stack spacing={SECTION_SPACING}>
        <Card variant="outlined">
          <CardContent>
            <Typography variant="h6" gutterBottom color="primary">
              Template Configuration
            </Typography>
            <Autocomplete
              options={templates ?? []}
              loading={templatesLoading}
              getOptionLabel={(option: TemplateResponse) => option.name}
              value={selectedTemplate}
              onChange={(_, value) => setTemplateId(value?.id ?? null)}
              isOptionEqualToValue={(option, value) => option.id === value.id}
              renderInput={(params) => (
                <TextField
                  {...params}
                  label="Select Template"
                  placeholder="Optional: Choose a template for custom fields"
                />
              )}
            />
          </CardContent>
        </Card>

        {selectedTemplate && selectedTemplate.fields.length > 0 && (
          <Card variant="outlined">
            <CardContent>
              <Typography variant="h6" gutterBottom color="primary">
                Custom Fields
              </Typography>
              <Grid container spacing={3}>
                {selectedTemplate.fields.map((field) => (
                  <Grid item xs={12} key={field.name}>
                    <TextField
                      fullWidth
                      required={field.required}
                      label={field.label}
                      value={customFields[field.name] || ''}
                      onChange={(e) =>
                        handleCustomFieldChange(field.name, e.target.value)
                      }
                      multiline={field.type === 'textarea'}
                      minRows={field.type === 'textarea' ? 3 : 1}
                      helperText={field.description}
                      variant="outlined"
                    />
                  </Grid>
                ))}
              </Grid>
            </CardContent>
          </Card>
        )}

        {/* Core Information */}
        <Card variant="outlined">
          <CardContent>
            <Typography variant="h6" gutterBottom color="primary">
              Core Information
            </Typography>
            <Grid container spacing={3}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  required
                  label="Front (Word/Phrase)"
                  value={front}
                  onChange={(e) => setFront(e.target.value)}
                  placeholder="e.g., 'Bonjour'"
                  helperText="The main term you want to learn."
                  variant="outlined"
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  required
                  label="Back (Translation/Definition)"
                  value={back}
                  onChange={(e) => setBack(e.target.value)}
                  multiline
                  minRows={2}
                  placeholder="e.g., 'Hello'"
                  variant="outlined"
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <Autocomplete
                  freeSolo
                  options={[
                    'noun',
                    'verb',
                    'adjective',
                    'adverb',
                    'preposition',
                    'conjunction',
                    'interjection',
                  ]}
                  value={partOfSpeech}
                  onChange={(_, v) => setPartOfSpeech(v || '')}
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      label="Part of Speech"
                      placeholder="e.g., noun"
                    />
                  )}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <Box display="flex" alignItems="center" gap={2}>
                  <Typography variant="body2" color="text.secondary">
                    Difficulty:
                  </Typography>
                  <ToggleButtonGroup
                    value={hardness}
                    exclusive
                    onChange={(_, v) => v && setHardness(v)}
                    size="small"
                    aria-label="hardness level"
                  >
                    <ToggleButton value="easy" color="success">
                      Easy
                    </ToggleButton>
                    <ToggleButton value="medium" color="warning">
                      Medium
                    </ToggleButton>
                    <ToggleButton value="hard" color="error">
                      Hard
                    </ToggleButton>
                  </ToggleButtonGroup>
                </Box>
              </Grid>
            </Grid>
          </CardContent>
        </Card>

        {/* Linguistic Details */}
        <Card variant="outlined">
          <CardContent>
            <Typography variant="h6" gutterBottom color="primary">
              Linguistic Details
            </Typography>
            <Grid container spacing={3}>
              <Grid item xs={12} md={4}>
                <Autocomplete
                  freeSolo
                  options={['masculine', 'feminine', 'neuter']}
                  value={gender}
                  onChange={(_, v) => setGender(v || '')}
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      label="Gender"
                      placeholder="e.g., masculine"
                    />
                  )}
                />
              </Grid>
              <Grid item xs={12} md={4}>
                <TextField
                  fullWidth
                  label="Plural Form"
                  value={pluralForm}
                  onChange={(e) => setPluralForm(e.target.value)}
                  placeholder="e.g., chats"
                />
              </Grid>
              <Grid item xs={12} md={4}>
                <TextField
                  fullWidth
                  label="Pronunciation"
                  value={pronunciation}
                  onChange={(e) => setPronunciation(e.target.value)}
                  placeholder="IPA (e.g., /bɔ̃.ʒuʁ/)"
                  InputProps={{
                    endAdornment: (
                      <Tooltip title="International Phonetic Alphabet representation">
                        <HelpOutlineIcon fontSize="small" color="action" />
                      </Tooltip>
                    ),
                  }}
                />
              </Grid>
            </Grid>
          </CardContent>
        </Card>

        {/* Examples */}
        <Card variant="outlined">
          <CardContent>
            <Box
              display="flex"
              justifyContent="space-between"
              alignItems="center"
              mb={2}
            >
              <Typography variant="h6" color="primary">
                Examples
              </Typography>
              <Button
                startIcon={<AddIcon />}
                onClick={() =>
                  setExamples([...examples, { sentence: '', translation: '' }])
                }
                disabled={examples.length >= 5}
                size="small"
              >
                Add Example
              </Button>
            </Box>
            <Stack spacing={2}>
              {examples.map((ex, i) => (
                <Paper
                  key={i}
                  elevation={0}
                  variant="outlined"
                  sx={{ p: 2, bgcolor: 'background.default' }}
                >
                  <Box display="flex" alignItems="flex-start" gap={2}>
                    <Grid container spacing={2} flex={1}>
                      <Grid item xs={12} md={6}>
                        <TextField
                          fullWidth
                          label={`Sentence ${i + 1}`}
                          value={ex.sentence}
                          onChange={(e) =>
                            handleExampleChange(i, 'sentence', e.target.value)
                          }
                          size="small"
                          placeholder="Example sentence using the word"
                        />
                      </Grid>
                      <Grid item xs={12} md={6}>
                        <TextField
                          fullWidth
                          label={`Translation ${i + 1}`}
                          value={ex.translation}
                          onChange={(e) =>
                            handleExampleChange(
                              i,
                              'translation',
                              e.target.value,
                            )
                          }
                          size="small"
                          placeholder="Translation of the example"
                        />
                      </Grid>
                    </Grid>
                    <IconButton
                      onClick={() =>
                        setExamples(examples.filter((_, idx) => idx !== i))
                      }
                      disabled={examples.length <= 1}
                      color="error"
                      size="small"
                    >
                      <DeleteIcon />
                    </IconButton>
                  </Box>
                </Paper>
              ))}
            </Stack>
          </CardContent>
        </Card>

        {/* Relationships */}
        <Card variant="outlined">
          <CardContent>
            <Typography variant="h6" gutterBottom color="primary">
              Relationships
            </Typography>
            <Grid container spacing={3}>
              <Grid item xs={12} md={6}>
                <Autocomplete
                  multiple
                  freeSolo
                  options={[]}
                  value={synonyms}
                  onChange={(_, v) => setSynonyms(v)}
                  renderTags={(value, getTagProps) =>
                    value.map((option, index) => (
                      <Chip
                        variant="outlined"
                        label={option}
                        size="small"
                        {...getTagProps({ index })}
                        key={index}
                      />
                    ))
                  }
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      label="Synonyms"
                      placeholder="Type and press Enter"
                      helperText="Words with similar meanings"
                    />
                  )}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <Autocomplete
                  multiple
                  freeSolo
                  options={[]}
                  value={antonyms}
                  onChange={(_, v) => setAntonyms(v)}
                  renderTags={(value, getTagProps) =>
                    value.map((option, index) => (
                      <Chip
                        variant="outlined"
                        label={option}
                        size="small"
                        {...getTagProps({ index })}
                        key={index}
                      />
                    ))
                  }
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      label="Antonyms"
                      placeholder="Type and press Enter"
                      helperText="Words with opposite meanings"
                    />
                  )}
                />
              </Grid>
            </Grid>
          </CardContent>
        </Card>

        {/* Metadata */}
        <Card variant="outlined">
          <CardContent>
            <Typography variant="h6" gutterBottom color="primary">
              Additional Notes & Tags
            </Typography>
            <Grid container spacing={3}>
              <Grid item xs={12}>
                <Autocomplete
                  multiple
                  freeSolo
                  options={[]}
                  value={tags}
                  onChange={(_, v) => setTags(v)}
                  renderTags={(value, getTagProps) =>
                    value.map((option, index) => (
                      <Chip
                        variant="outlined"
                        label={option}
                        size="small"
                        {...getTagProps({ index })}
                        key={index}
                      />
                    ))
                  }
                  renderInput={(params) => (
                    <TextField
                      {...params}
                      label="Tags"
                      placeholder="Type and press Enter"
                    />
                  )}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="Notes"
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  multiline
                  minRows={3}
                  placeholder="Any extra context, usage notes, or mnemonic devices..."
                />
              </Grid>
            </Grid>
          </CardContent>
        </Card>

        <Box display="flex" justifyContent="flex-end" pt={2} pb={4}>
          <Button
            type="submit"
            variant="contained"
            size="large"
            disabled={isLoading || !front.trim() || !back.trim()}
            sx={{ px: 4, py: 1.5 }}
          >
            {isLoading ? 'Saving...' : submitLabel}
          </Button>
        </Box>
      </Stack>
    </Box>
  )
}

import { useState, useEffect } from 'react'
import Dialog from '@mui/material/Dialog'
import DialogTitle from '@mui/material/DialogTitle'
import DialogContent from '@mui/material/DialogContent'
import DialogActions from '@mui/material/DialogActions'
import Button from '@mui/material/Button'
import TextField from '@mui/material/TextField'
import Grid from '@mui/material/Grid2'
import Box from '@mui/material/Box'
import Typography from '@mui/material/Typography'
import IconButton from '@mui/material/IconButton'
import Autocomplete from '@mui/material/Autocomplete'
import Chip from '@mui/material/Chip'
import Divider from '@mui/material/Divider'
import CircularProgress from '@mui/material/CircularProgress'
import Paper from '@mui/material/Paper'
import Stack from '@mui/material/Stack'
import AddIcon from '@mui/icons-material/Add'
import DeleteIcon from '@mui/icons-material/Delete'
import EditIcon from '@mui/icons-material/Edit'
import TranslateIcon from '@mui/icons-material/Translate'
import SchoolIcon from '@mui/icons-material/School'
import MenuBookIcon from '@mui/icons-material/MenuBook'
import LocalOfferIcon from '@mui/icons-material/LocalOffer'
import type {
  DraftCardResponse,
  DraftCardUpdate,
  ExampleSentence,
} from '../../types'

interface DraftEditDialogProps {
  open: boolean
  draft: DraftCardResponse | null
  onClose: () => void
  onSave: (data: DraftCardUpdate) => void
  isSaving: boolean
}

export default function DraftEditDialog({
  open,
  draft,
  onClose,
  onSave,
  isSaving,
}: DraftEditDialogProps) {
  const [front, setFront] = useState('')
  const [back, setBack] = useState('')
  const [examples, setExamples] = useState<ExampleSentence[]>([])
  const [synonyms, setSynonyms] = useState<string[]>([])
  const [antonyms, setAntonyms] = useState<string[]>([])
  const [partOfSpeech, setPartOfSpeech] = useState('')
  const [gender, setGender] = useState('')
  const [pluralForm, setPluralForm] = useState('')
  const [pronunciation, setPronunciation] = useState('')
  const [notes, setNotes] = useState('')
  const [tags, setTags] = useState<string[]>([])

  // Reset form when draft changes
  useEffect(() => {
    if (draft) {
      setFront(draft.front)
      setBack(draft.back)
      setExamples(draft.examples ?? [])
      setSynonyms(draft.synonyms ?? [])
      setAntonyms(draft.antonyms ?? [])
      setPartOfSpeech(draft.part_of_speech ?? '')
      setGender(draft.gender ?? '')
      setPluralForm(draft.plural_form ?? '')
      setPronunciation(draft.pronunciation ?? '')
      setNotes(draft.notes ?? '')
      setTags(draft.tags ?? [])
    }
  }, [draft])

  const handleExampleChange = (
    index: number,
    field: keyof ExampleSentence,
    value: string,
  ) => {
    const updated = [...examples]
    updated[index] = { ...updated[index], [field]: value }
    setExamples(updated)
  }

  const handleAddExample = () => {
    setExamples([...examples, { sentence: '', translation: '' }])
  }

  const handleRemoveExample = (index: number) => {
    setExamples(examples.filter((_, i) => i !== index))
  }

  const handleSave = () => {
    const filteredExamples = examples.filter(
      (ex) => ex.sentence.trim() || ex.translation.trim(),
    )

    const data: DraftCardUpdate = {
      front: front || undefined,
      back: back || undefined,
      examples: filteredExamples.length > 0 ? filteredExamples : undefined,
      synonyms: synonyms.length > 0 ? synonyms : undefined,
      antonyms: antonyms.length > 0 ? antonyms : undefined,
      part_of_speech: partOfSpeech || undefined,
      gender: gender || undefined,
      plural_form: pluralForm || undefined,
      pronunciation: pronunciation || undefined,
      notes: notes || undefined,
      tags: tags.length > 0 ? tags : undefined,
    }

    onSave(data)
  }

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="md"
      fullWidth
      PaperProps={{
        sx: { borderRadius: 2 },
      }}
    >
      <DialogTitle
        sx={{ borderBottom: '1px solid', borderColor: 'divider', pb: 2 }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
          <Box
            sx={{
              p: 1,
              bgcolor: 'primary.light',
              borderRadius: 1,
              color: 'primary.contrastText',
              display: 'flex',
            }}
          >
            <EditIcon fontSize="small" />
          </Box>
          <Typography variant="h6" fontWeight={600}>
            Edit Flashcard Draft
          </Typography>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ bgcolor: 'grey.50', p: 3 }}>
        <Stack spacing={3} sx={{ mt: 1 }}>
          {/* Core Fields Section */}
          <Paper
            variant="outlined"
            sx={{
              p: 2.5,
              borderRadius: 2,
              borderLeft: '4px solid',
              borderLeftColor: 'primary.main',
              bgcolor: 'background.paper',
            }}
          >
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
              <TranslateIcon color="primary" fontSize="small" />
              <Typography
                variant="subtitle2"
                fontWeight={700}
                color="text.secondary"
                sx={{ letterSpacing: 0.5 }}
              >
                CORE CONTENT
              </Typography>
            </Box>
            <Grid container spacing={2}>
              <Grid size={{ xs: 12, md: 6 }}>
                <TextField
                  fullWidth
                  label="Front (word/phrase)"
                  value={front}
                  onChange={(e) => setFront(e.target.value)}
                  multiline
                  variant="outlined"
                  slotProps={{ inputLabel: { shrink: true } }}
                />
              </Grid>
              <Grid size={{ xs: 12, md: 6 }}>
                <TextField
                  fullWidth
                  label="Back (translation)"
                  value={back}
                  onChange={(e) => setBack(e.target.value)}
                  multiline
                  variant="outlined"
                  slotProps={{ inputLabel: { shrink: true } }}
                />
              </Grid>
            </Grid>
          </Paper>

          {/* Linguistics Section */}
          <Paper
            variant="outlined"
            sx={{ p: 2.5, borderRadius: 2, bgcolor: 'background.paper' }}
          >
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
              <SchoolIcon color="action" fontSize="small" />
              <Typography
                variant="subtitle2"
                fontWeight={700}
                color="text.secondary"
                sx={{ letterSpacing: 0.5 }}
              >
                LINGUISTICS
              </Typography>
            </Box>
            <Grid container spacing={2}>
              <Grid size={{ xs: 12, md: 6, lg: 3 }}>
                <TextField
                  fullWidth
                  label="Part of Speech"
                  value={partOfSpeech}
                  onChange={(e) => setPartOfSpeech(e.target.value)}
                  placeholder="noun, verb..."
                  size="small"
                  slotProps={{ inputLabel: { shrink: true } }}
                />
              </Grid>
              <Grid size={{ xs: 12, md: 6, lg: 3 }}>
                <TextField
                  fullWidth
                  label="Gender"
                  value={gender}
                  onChange={(e) => setGender(e.target.value)}
                  placeholder="m, f, n"
                  size="small"
                  slotProps={{ inputLabel: { shrink: true } }}
                />
              </Grid>
              <Grid size={{ xs: 12, md: 6, lg: 3 }}>
                <TextField
                  fullWidth
                  label="Plural Form"
                  value={pluralForm}
                  onChange={(e) => setPluralForm(e.target.value)}
                  size="small"
                  slotProps={{ inputLabel: { shrink: true } }}
                />
              </Grid>
              <Grid size={{ xs: 12, md: 6, lg: 3 }}>
                <TextField
                  fullWidth
                  label="Pronunciation"
                  value={pronunciation}
                  onChange={(e) => setPronunciation(e.target.value)}
                  placeholder="IPA"
                  size="small"
                  slotProps={{ inputLabel: { shrink: true } }}
                />
              </Grid>
            </Grid>
          </Paper>

          {/* Examples Section */}
          <Paper
            variant="outlined"
            sx={{ p: 2.5, borderRadius: 2, bgcolor: 'background.paper' }}
          >
            <Box
              sx={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
                mb: 2,
              }}
            >
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <MenuBookIcon color="action" fontSize="small" />
                <Typography
                  variant="subtitle2"
                  fontWeight={700}
                  color="text.secondary"
                  sx={{ letterSpacing: 0.5 }}
                >
                  CONTEXT & EXAMPLES
                </Typography>
              </Box>
              <Button
                startIcon={<AddIcon />}
                onClick={handleAddExample}
                size="small"
                disabled={examples.length >= 5}
              >
                Add Example
              </Button>
            </Box>

            <Stack spacing={2}>
              {examples.length === 0 && (
                <Typography
                  variant="body2"
                  color="text.secondary"
                  sx={{ fontStyle: 'italic', textAlign: 'center', py: 2 }}
                >
                  No examples added yet.
                </Typography>
              )}
              {examples.map((ex, i) => (
                <Box
                  key={i}
                  sx={{
                    display: 'flex',
                    gap: 1.5,
                    alignItems: 'start',
                    p: 1.5,
                    bgcolor: 'action.hover',
                    borderRadius: 1,
                  }}
                >
                  <Chip
                    label={i + 1}
                    size="small"
                    sx={{ height: 24, minWidth: 24 }}
                  />
                  <Grid container spacing={1} sx={{ flex: 1 }}>
                    <Grid size={{ xs: 12 }}>
                      <TextField
                        fullWidth
                        placeholder="Example sentence"
                        value={ex.sentence}
                        onChange={(e) =>
                          handleExampleChange(i, 'sentence', e.target.value)
                        }
                        size="small"
                        variant="standard"
                        slotProps={{
                          input: {
                            disableUnderline: true,
                            style: { fontWeight: 500 },
                          },
                        }}
                      />
                    </Grid>
                    <Grid size={{ xs: 12 }}>
                      <TextField
                        fullWidth
                        placeholder="Translation"
                        value={ex.translation}
                        onChange={(e) =>
                          handleExampleChange(i, 'translation', e.target.value)
                        }
                        size="small"
                        variant="standard"
                        slotProps={{
                          input: {
                            disableUnderline: true,
                            style: {
                              color: 'text.secondary',
                              fontSize: '0.9em',
                            },
                          },
                        }}
                      />
                    </Grid>
                  </Grid>
                  <IconButton
