  Button,
  TextField,
  Box,
} from '@mui/material'
import type {
  TemplateUpdate,
  TemplateResponse,
  TemplateFieldSchema,
} from '../../types'
import { createTemplate, updateTemplate } from '../../api/templates'
import { useMutation, useQueryClient } from '@tanstack/react-query'
import TemplateVisualEditor, { EditorField } from './TemplateVisualEditor'

interface TemplateFormModalProps {
  open: boolean
  onClose: () => void
  template: TemplateResponse | null
}

const emptyField: TemplateFieldSchema = {
  name: '',
  label: '',
  type: 'text',
  description: '',
  show_on_front: true,
  required: false,
}

export default function TemplateFormModal({
  open,
  onClose,
  template,
}: TemplateFormModalProps) {
  const queryClient = useQueryClient()
  const [name, setName] = useState('')
  const [description, setDescription] = useState('')
  const [systemPrompt, setSystemPrompt] = useState('')
  const [fields, setFields] = useState<EditorField[]>([])

  useEffect(() => {
    if (template) {
      setName(template.name)
      setDescription(template.description || '')
      setSystemPrompt(template.system_prompt || '')
      setFields(
        template.fields.map((f, i) => ({
          ...f,
          id: `field-${i}-${Date.now()}`, // Attach temporary ID for dnd-kit
        })),
      )
    } else {
      setName('')
      setDescription('')
      setSystemPrompt('')
      setFields([
        {
          ...emptyField,
          name: 'front',
          label: 'Front',
          id: `field-front-${Date.now()}`,
        },
        {
          ...emptyField,
          name: 'back',
          label: 'Back',
          show_on_front: false,
          id: `field-back-${Date.now()}`,
        },
      ])
    }
  }, [template, open])

  const createMutation = useMutation({
    mutationFn: createTemplate,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['templates'] })
      onClose()
    },
  })

  const updateMutation = useMutation({
    mutationFn: (data: { id: string; update: TemplateUpdate }) =>
      updateTemplate(data.id, data.update),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['templates'] })
      onClose()
    },
  })

  const handleSave = () => {
    const data = {
      name,
      description,
      system_prompt: systemPrompt,
      fields: fields.map((f) => {
        // Strip out the local 'id' required by the editor before saving
        const { id, ...rest } = f
        return {
          ...rest,
          // sanitize name
          name: rest.name.toLowerCase().replace(/\s+/g, '_'),
        }
      }),
    }

    if (template) {
      updateMutation.mutate({ id: template.id, update: data })
    } else {
      createMutation.mutate(data)
    }
  }

  return (
    <Dialog open={open} onClose={onClose} maxWidth="xl" fullWidth>
      <DialogTitle>{template ? 'Edit Template' : 'New Template'}</DialogTitle>
      <DialogContent dividers>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3, my: 1 }}>
          <Box sx={{ display: 'flex', gap: 2 }}>
            <TextField
              label="Template Name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              sx={{ width: '30%' }}
              required
            />
            <TextField
              label="Description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              sx={{ width: '70%' }}
            />
          </Box>
          <TextField
            label="AI System Prompt Instructions"
            value={systemPrompt}
            onChange={(e) => setSystemPrompt(e.target.value)}
            fullWidth
            multiline
            rows={2}
            helperText="Instructions to guide Gemini on how to extract and populate these fields."
          />

          <Box mt={2}>
            <TemplateVisualEditor fields={fields} onChange={setFields} />
          </Box>
        </Box>
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose}>Cancel</Button>
        <Button
          variant="contained"
          onClick={handleSave}
          disabled={!name || fields.length === 0}
        >
          Save
        </Button>
      </DialogActions>
    </Dialog>
  )
}

import {
  createContext,
  useContext,
  useState,
  useCallback,
  type ReactNode,
} from 'react'
import { login as apiLogin, register as apiRegister } from '../api/auth'
import type { RegisterData } from '../types'

interface AuthContextValue {
  token: string | null
  isAuthenticated: boolean
  login: (username: string, password: string) => Promise<void>
  register: (data: RegisterData) => Promise<void>
  logout: () => void
}

const AuthContext = createContext<AuthContextValue | null>(null)

export function AuthProvider({ children }: { children: ReactNode }) {
  const [token, setToken] = useState<string | null>(() =>
    localStorage.getItem('access_token'),
  )

  const login = useCallback(async (username: string, password: string) => {
    const result = await apiLogin(username, password)
    localStorage.setItem('access_token', result.access_token)
    setToken(result.access_token)
  }, [])

  const register = useCallback(
    async (data: RegisterData) => {
      await apiRegister(data)
      await login(data.username, data.password)
    },
    [login],
  )

  const logout = useCallback(() => {
    localStorage.removeItem('access_token')
    setToken(null)
  }, [])

  return (
    <AuthContext.Provider
      value={{ token, isAuthenticated: !!token, login, register, logout }}
    >
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) throw new Error('useAuth must be used within AuthProvider')
  return context
}

