            background: (theme) =>
              `linear-gradient(135deg, ${theme.palette.primary.main}15 0%, ${theme.palette.secondary.main}15 100%)`,
            border: (theme) => `1px solid ${theme.palette.divider}`,
          }}
        >
          <Stack spacing={2} alignItems="center">
            <AutoAwesomeIcon sx={{ fontSize: 48, color: 'primary.main' }} />
            <Typography variant="h6" fontWeight={600}>
              Ready to Generate Flashcards?
            </Typography>
            <Typography
              variant="body2"
              color="text.secondary"
              sx={{ maxWidth: 500 }}
            >
              Upload a book or select an existing one to generate flashcards
            </Typography>
            <Stack direction="row" spacing={2} sx={{ mt: 2 }}>
              <Button
                variant="outlined"
                size="large"
                startIcon={<CloudUploadIcon />}
                onClick={() => setUploadOpen(true)}
                sx={{ px: 3, py: 1.5 }}
              >
                Upload Book
              </Button>
              <Button
                variant="contained"
                size="large"
                startIcon={<AddIcon />}
                onClick={() => setDialogOpen(true)}
                sx={{ px: 4, py: 1.5 }}
              >
                Generate Flashcards
              </Button>
            </Stack>
          </Stack>
        </Paper>
      </Box>

      {/* Success Message */}
      {lastResult && (
        <Paper
          sx={{
            p: 2,
            mb: 4,
            bgcolor: 'success.main',
            color: 'success.contrastText',
          }}
        >
          <Typography variant="body1" fontWeight={600}>
            {lastResult.message}
          </Typography>
          <Typography variant="body2" sx={{ opacity: 0.9 }}>
            Generated {lastResult.drafts.length} draft cards from pages{' '}
            {lastResult.pages_processed.start}–{lastResult.pages_processed.end}
          </Typography>
        </Paper>
      )}

      {/* Review section */}
      <Box>
        <Typography variant="h5" component="h2" fontWeight={600} gutterBottom>
          Review Drafts
        </Typography>
        <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
          Review, edit, and approve generated drafts to add them to your card
          collection.
        </Typography>
        <DraftReviewList bookId={selectedBookId ?? undefined} />
      </Box>

      {/* Generate Dialog */}
      <GenerateDialog
        open={dialogOpen}
        onClose={() => setDialogOpen(false)}
        selectedBookId={selectedBookId}
        onBookChange={setSelectedBookId}
        onSuccess={handleGenerateSuccess}
      />

      {/* Upload Book Dialog */}
      <BookUploadDialog
        open={uploadOpen}
        onClose={() => setUploadOpen(false)}
        onSuccess={handleUploadSuccess}
      />
    </Box>
  )
}

import {
  createRouter,
  createRoute,
  createRootRoute,
  redirect,
} from '@tanstack/react-router'
import { lazy } from 'react'
import AppLayout from '../components/layout/AppLayout'
import ProtectedRoute from '../components/auth/ProtectedRoute'

// Lazy load all page components
const LoginPage = lazy(() => import('../pages/LoginPage'))
const RegisterPage = lazy(() => import('../pages/RegisterPage'))
const DashboardPage = lazy(() => import('../pages/DashboardPage'))
const CardsListPage = lazy(() => import('../pages/CardsListPage'))
const CardCreatePage = lazy(() => import('../pages/CardCreatePage'))
const CardDetailPage = lazy(() => import('../pages/CardDetailPage'))
const CardEditPage = lazy(() => import('../pages/CardEditPage'))
const DecksListPage = lazy(() => import('../pages/DecksListPage'))
const DeckCreatePage = lazy(() => import('../pages/DeckCreatePage'))
const DeckDetailPage = lazy(() => import('../pages/DeckDetailPage'))
const BooksListPage = lazy(() => import('../pages/BooksListPage'))
const BookDetailPage = lazy(() => import('../pages/BookDetailPage'))
const GenerationPage = lazy(() => import('../pages/GenerationPage'))
const StorageSettingsPage = lazy(() => import('../pages/StorageSettingsPage'))
const TemplatesPage = lazy(() => import('../pages/TemplatesPage'))

// Root route
const rootRoute = createRootRoute()

// Public routes
const loginRoute = createRoute({
  getParentRoute: () => rootRoute,
  path: '/login',
  component: LoginPage,
})

const registerRoute = createRoute({
  getParentRoute: () => rootRoute,
  path: '/register',
  component: RegisterPage,
})

// Authenticated layout route
const authLayoutRoute = createRoute({
  getParentRoute: () => rootRoute,
  id: 'auth',
  component: () => <ProtectedRoute />,
})

const appLayoutRoute = createRoute({
  getParentRoute: () => authLayoutRoute,
  id: 'app',
  component: AppLayout,
})

// Index redirect
const indexRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/',
  beforeLoad: () => {
    throw redirect({ to: '/dashboard' })
  },
})

// Dashboard
const dashboardRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/dashboard',
  component: DashboardPage,
})

// Cards
const cardsRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/cards',
  component: CardsListPage,
})

const cardCreateRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/cards/new',
  component: CardCreatePage,
})

const cardDetailRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/cards/$cardId',
  component: CardDetailPage,
})

const cardEditRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/cards/$cardId/edit',
  component: CardEditPage,
})

// Decks
const decksRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/decks',
  component: DecksListPage,
})

const deckCreateRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/decks/new',
  component: DeckCreatePage,
})

const deckDetailRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/decks/$deckId',
  component: DeckDetailPage,
})

// Books
const booksRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/books',
  component: BooksListPage,
})

const bookDetailRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/books/$bookId',
  component: BookDetailPage,
})

// Generation
const generationRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/generation',
  component: GenerationPage,
})

// Settings
const storageSettingsRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/settings/storage',
  component: StorageSettingsPage,
})

// Templates
const templatesRoute = createRoute({
  getParentRoute: () => appLayoutRoute,
  path: '/templates',
  component: TemplatesPage,
})

// Build route tree
const routeTree = rootRoute.addChildren([
  loginRoute,
  registerRoute,
  authLayoutRoute.addChildren([
    appLayoutRoute.addChildren([
      indexRoute,
      dashboardRoute,
      cardsRoute,
      cardCreateRoute,
      cardDetailRoute,
      cardEditRoute,
      decksRoute,
      deckCreateRoute,
      deckDetailRoute,
      booksRoute,
      bookDetailRoute,
      generationRoute,
      storageSettingsRoute,
      templatesRoute,
    ]),
  ]),
])

export const router = createRouter({ routeTree })

declare module '@tanstack/react-router' {
  interface Register {
    router: typeof router
  }
}

import {
  createContext,
  useContext,
  useState,
  useMemo,
  useCallback,
  type ReactNode,
} from 'react'
import { ThemeProvider } from '@mui/material/styles'
import CssBaseline from '@mui/material/CssBaseline'
import { getTheme } from './theme'

interface ThemeContextValue {
  mode: 'light' | 'dark'
  toggleTheme: () => void
}

const ThemeContext = createContext<ThemeContextValue>({
  mode: 'light',
  toggleTheme: () => {},
})

export function ThemeContextProvider({ children }: { children: ReactNode }) {
  const [mode, setMode] = useState<'light' | 'dark'>(
    () => (localStorage.getItem('theme_mode') as 'light' | 'dark') || 'dark',
  )

  const toggleTheme = useCallback(() => {
    setMode((prev) => {
      const next = prev === 'light' ? 'dark' : 'light'
      localStorage.setItem('theme_mode', next)
      return next
    })
  }, [])

  const theme = useMemo(() => getTheme(mode), [mode])

  return (
    <ThemeContext.Provider value={{ mode, toggleTheme }}>
      <ThemeProvider theme={theme}>
        <CssBaseline />
        {children}
      </ThemeProvider>
    </ThemeContext.Provider>
  )
}

export function useThemeMode() {
  return useContext(ThemeContext)
}
